function calculateDiscount(age, isMember) {
    let discount = 0;
    if (age < 18) {
        discount = 0.20;
    } else {
        if (isMember) {
            discount = 0.15;
        } else {
            discount = 0.05;
        }
    }
    return discount;
}

function findElement(arr, target) {
    let index = -1;
    for (let i = 0; i < arr.length; i++) {
        if (arr[i] === target) {
            index = i;
            break;
        }
    }
    return index;
}

function getTrafficLightAction(color) {
    let action;
    switch (color) {
        case 'rosu':
            action = 'Stop';
            break;
        case 'galben':
            action = 'Atentie';
            break;
        case 'verde':
            action = 'Mergi';
            break;
        default:
            action = 'Eroare semnal';
    }
    return action;
}
